      border: 1px solid #eee;
      border-radius: 16px;
      padding: 14px;
      transition: 0.2s;
      position: relative;
    }

    .product-card:hover {
      box-shadow: 0 6px 18px rgba(0,0,0,0.08);
      transform: translateY(-3px);
    }

    .discount {
      position: absolute;
      top: 12px;
      right: 12px;
      background: #ef4056;
      color: white;
      border-radius: 20px;
      padding: 3px 9px;
      font-size: 12px;
