      }

      .products {
        grid-template-columns: repeat(3, 1fr);
      }
    }

    @media (max-width: 650px) {
      .top-header {
        flex-wrap: wrap;
      }

      .logo {
        width: 100%;
        text-align: center;
      }

      .header-actions {
        width: 100%;
        justify-content: space-between;
      }

      .hero,
      .two-banners {
        grid-template-columns: 1fr;
      }

      .main-banner h1 {
        font-size: 25px;
      }

      .categories {
        grid-template-columns: repeat(3, 1fr);
      }

      .products {
        grid-template-columns: repeat(2, 1fr);
      }

      .product-img {
        height: 120px;
        font-size: 42px;
      }
    }
  </style>
</head>

