  <script>
    const themeBtn = document.getElementById("themeBtn");
    const cartCount = document.getElementById("cartCount");
    const searchInput = document.getElementById("searchInput");
    const products = document.querySelectorAll(".product-card");
    const emptyMessage = document.getElementById("emptyMessage");
    const showProductsBtn = document.getElementById("showProductsBtn");
    const loginBtn = document.getElementById("loginBtn");
    const cartBtn = document.getElementById("cartBtn");

    let cart = 0;

    themeBtn.addEventListener("click", () => {
      document.body.classList.toggle("dark");

      if (document.body.classList.contains("dark")) {
        themeBtn.textContent = "☀️ لایت";
      } else {
        themeBtn.textContent = "🌙 دارک";
      }
    });

    document.querySelectorAll(".add-cart").forEach(btn => {
      btn.addEventListener("click", () => {
        cart++;
        cartCount.textContent = cart;
        btn.textContent = "اضافه شد ✓";
        btn.style.background = "#00a86b";

        setTimeout(() => {
          btn.textContent = "افزودن به سبد";
          btn.style.background = "#ef4056";
        }, 1000);
      });
    });

    searchInput.addEventListener("input", () => {
      const value = searchInput.value.trim().toLowerCase();
      let visibleCount = 0;

      products.forEach(product => {
        const name = product.dataset.name.toLowerCase();
        const title = product.innerText.toLowerCase();

        if (name.includes(value) || title.includes(value)) {
          product.style.display = "block";
          visibleCount++;
        } else {
          product.style.display = "none";
        }
      });

      emptyMessage.style.display = visibleCount === 0 ? "block" : "none";
    });

    function filterProducts(category) {
      let visibleCount = 0;

      products.forEach(product => {
        if (category === "all" || product.dataset.category === category) {
          product.style.display = "block";
          visibleCount++;
        } else {
          product.style.display = "none";
        }
      });

      emptyMessage.style.display = visibleCount === 0 ? "block" : "none";

      document.getElementById("productsSection").scrollIntoView({
        behavior: "smooth"
      });
    }

    showProductsBtn.addEventListener("click", () => {
      document.getElementById("productsSection").scrollIntoView({
        behavior: "smooth"
      });
    });

    loginBtn.addEventListener("click", () => {
      alert("صفحه ورود هنوز ساخته نشده، بابا. مرحله بعدی برات مودال ورود می‌سازم.");
    });

    cartBtn.addEventListener("click", () => {
      alert("تعداد محصولات داخل سبد خرید: " + cart);
    });
  </script>

